#include "tensorflow/core/lib/core/errors.h"
#include "tensorflow/core/lib/core/status.h"
#include "tensorflow/core/lib/gtl/array_slice.h"
#include "tensorflow/core/platform/logging.h"
#include "tensorflow/core/util/str_util.h"

namespace tensorflow {

class RowPartitionOp : public OpKernel {
 public:
  explicit RowPartitionOp(OpKernelConstruction* context) : OpKernel(context) {}

  void Compute(OpKernelContext* context) override {
    const Tensor& row_partition_tensor = context->input(0);
    const Tensor& row_partition_type = context->input(1);
    const Tensor& output_size_tensor = context->input(2);

    OP_REQUIRES(context, row_partition_tensor.dims() == 1,
                errors::InvalidArgument("row_partition must be a 1-D tensor"));
    OP_REQUIRES(context, row_partition_type.dims() == 0,
                errors::InvalidArgument("row_partition_type must be a scalar"));
    OP_REQUIRES(context, output_size_tensor.dims() == 0,
                errors::InvalidArgument("output_size must be a scalar"));

    const int64 num_partitions = row_partition_tensor.dim_size(0);
    const int64 output_size = output_size_tensor.scalar<int64>()();

    OP_REQUIRES(context, num_partitions >= 0,
                errors::InvalidArgument("num_partitions must be non-negative"));
    OP_REQUIRES(context, output_size >= 0,
                errors::InvalidArgument("output_size must be non-negative"));

    // Validate partition size against output size.
    if (num_partitions > 0) {
      const int64 partition_size = row_partition_tensor.flat<int64>()(0);
      OP_REQUIRES(context, partition_size >= 0,
                  errors::InvalidArgument("partition_size must be non-negative"));
      OP_REQUIRES(context, partition_size > 0,
                  errors::InvalidArgument("partition_size must be positive"));
      OP_REQUIRES(context, output_size % partition_size == 0,
                  errors::InvalidArgument(
                      "output_size must be divisible by partition_size"));
    }

    // Create the output tensor.
    Tensor* output = nullptr;
    OP_REQUIRES_OK(context, context->allocate_output(0, TensorShape({num_partitions}),
                                                     &output));

    // Fill the output tensor.
    auto output_flat = output->flat<int64>();
    for (int64 i = 0; i < num_partitions; ++i) {
      output_flat(i) = i * output_size / num_partitions;
    }
  }
};

REGISTER_KERNEL_BUILDER(Name("RowPartition").Device(DEVICE_CPU), RowPartitionOp);

}  // namespace tensorflow
