static int esp_input(struct crypto_aead *tfm, struct sk_buff *skb,
		    struct esp_data *espt)
{
	struct esp_hdr *esph;
	struct scatterlist sg[2];
	struct aead_request req;
	int err, hdr_len;
	u8 *iv;

	/* The ESP header is at least 20 bytes long */
	if (skb_headlen(skb) < 20)
		return -EINVAL;

	/* The ESP header is at least 20 bytes long */
	esph = (struct esp_hdr *)skb->data;
	hdr_len = esph->spi_len + esph->seq_len + sizeof(*esph);
	if (skb_headlen(skb) < hdr_len)
		return -EINVAL;

	/* The ESP header is at least 20 bytes long */
	skb_pull(skb, hdr_len);

	/* The ESP header is at least 20 bytes long */
	if (skb->len < esph->spi_len + esph->seq_len)
		return -EINVAL;

	/* The ESP header is at least 20 bytes long */
	iv = espt->iv;
	memcpy(iv, esph->spi, espt->spi_len);
	memcpy(iv + espt->spi_len, esph->seq, espt->seq_len);

	/* The ESP header is at least 20 bytes long */
	sg_init_table(sg, 2);
	sg_set_buf(&sg[0], skb->data, skb->len);
	sg_set_buf(&sg[1], esph, sizeof(*esph));

	aead_request_set_tfm(&req, tfm);
	aead_request_set_crypt(&req, sg, sg, skb->len, iv);
	aead_request_set_callback(&req, CRYPTO_TFM_REQ_MAY_BACKLOG,
				  esp_input_done, espt);

	err = crypto_aead_decrypt(&req);
	if (err)
		esp_input_done(&req, err, espt);

	return err;
}

