	char *cmd;
	pid_t pid;
	int status;

	if (asprintf(&cmd, "cp -p %s %s", src, dest) < 0)
		return -ENOMEM;

	pid = fork();
	if (pid < 0)
		return -errno;
	if (pid == 0) {
		if (chown(dest, 0, 0) < 0)
			_exit(EXIT_FAILURE);
		if (chmod(dest, 0644) < 0)
			_exit(EXIT_FAILURE);
