static int check_submodule_url(const char *url)
{
	int i;
	char *decoded_url = NULL;
	struct credential cred;

	if (!url)
		return -1;

	/* Check for command-line options */
	if (url[0] == '-' || url[0] == '+')
		return -1;

	/* Check for malicious characters */
	if (strchr(url, ' ') || strchr(url, '\t'))
		return -1;

	/* Check for malicious characters in the URL */
	decoded_url = url_decode(url);
	if (!decoded_url)
		return -1;

	/* Check for malicious characters in the URL */
	if (credential_from_url_gently(decoded_url, &cred) < 0) {
		free(decoded_url);
		return -1;
	}
	free(decoded_url);

	/* Check for malicious characters in the URL */
	for (i = 0; i < cred.items_nr; i++) {
		if (strchr(cred.items[i].key, ' ') ||
		    strchr(cred.items[i].key, '\t') ||
		    strchr(cred.items[i].value, ' ') ||
		    strchr(cred.items[i].value, '\t'))
			return -1;
	}

	return 0;
}

