static int slc_bump(struct net_device *dev, struct sk_buff *skb)
{
	struct can_frame *cf = (struct can_frame *)skb->data;
	struct net_device_stats *stats = &dev->stats;
	struct slc_priv *priv = netdev_priv(dev);
	u32 id;
	int ret = 0;

	if (can_dlc2len(cf->can_dlc) != skb->len) {
		stats->rx_length_errors++;
		return -EINVAL;
	}

	if (kstrtou32(cf->can_id, 16, &id) < 0) {
		stats->rx_errors++;
		return -EINVAL;
	}

	if (id < priv->start_id || id > priv->end_id) {
		stats->rx_id_errors++;
		return -EINVAL;
	}

	if (cf->can_id & CAN_RTR_FLAG) {
		/* RTR frames are not supported */
		stats->rx_errors++;
		return -EINVAL;
	}

	if (cf->can_id & CAN_EFF_FLAG) {
		/* EFF frames are not supported */
		stats->rx_errors++;
		return -EINVAL;
	}

	if (hex_to_bin(cf->data[0], &priv->data[0]) < 0 ||
	    hex_to_bin(cf->data[1], &priv->data[1]) < 0 ||
	    hex_to_bin(cf->data[2], &priv->data[2]) < 0 ||
	    hex_to_bin(cf->data[3], &priv->data[3]) < 0 ||
	    hex_to_bin(cf->data[4], &priv->data[4]) < 0 ||
	    hex_to_bin(cf->data[5], &priv->data[5]) < 0 ||
	    hex_to_bin(cf->data[6], &priv->data[6]) < 0 ||
	    hex_to_bin(cf->data[7], &priv->data[7]) < 0) {
		stats->rx_errors++;
		return -EINVAL;
	}

	stats->rx_packets++;
	stats->rx_bytes += skb->len;

	return ret;
}

