```cpp
#include <tensorflow/core/framework/op_kernel.h>
#include <tensorflow/core/framework/tensor.h>
#include <tensorflow/core/framework/tensor_shape.h>
#include <tensorflow/core/framework/types.h>
#include <tensorflow/core/lib/core/status.h>
#include <tensorflow/core/util/ragged_util.h>

using namespace tensorflow;

class RaggedTensorToTensorOp : public OpKernel {
 public:
  explicit RaggedTensorToTensorOp(OpKernelConstruction* context)
      : OpKernel(context) {}

  void Compute(OpKernelContet* context) override {
    const Tensor& ragged_splits = context->input(0);
    const Tensor& ragged_values = context->input(1);

    OP_REQUIRES(context, ragged_splits.dims() == 1,
                errors::InvalidArgument("ragged_splits must be rank 1"));
    OP_REQUIRES(context, ragged_values.dims() == 2,
                errors::InvalidArgument("ragged_values must be rank 2"));
    OP_REQUIRES(context, ragged_splits.dtype() == DT_INT32,
                errors::InvalidArgument("ragged_splits must be of type int32"));
    OP_REQUIRES(context, ragged_values.dtype() == DT_INT32,
                errors::InvalidArgument("ragged_values must be of type int32"));

    const TensorShape& splits_shape = ragged_splits.shape();
    const TensorShape& values_shape = ragged_values.shape();

    OP_REQUIRES(context, splits_shape.dim_size(0) == values_shape.dim_size(0),
                errors::InvalidArgument(
                    "ragged_splits and ragged_values must have the same "
                    "number of splits"));
    OP_REQUIRES(context, splits_shape.dim_size(1) == 1,
                errors::InvalidArgument("ragged_splits must be rank 1"));
    OP_REQUIRES(context, values_shape.dim_size(1) == 1,
                errors::InvalidArgument("ragged_values must be rank 2"));

    const int64 num_splits = splits_shape.dim_size(0);
    const int64 values_length = values_shape.dim_size(0);

    // Validate ragged_splits
    OP_REQUIRES(context, ragged_splits.flat<int32>()(0) == 0,
                errors::InvalidArgument(
                    "ragged_splits must start with 0, but got ",
                    ragged_splits.flat<int32>()(0)));
    for (int64 i = 1; i < num_splits; ++i) {
      OP_REQUIRES(context, ragged_splits.flat<int32>()(i) >=
                              ragged_splits.flat<int32>()(i - 1),
                  errors::InvalidArgument(
                      "ragged_splits must be sorted in non-decreasing order, "
                      "but got ragged_splits(", i - 1, ") = ",
                      ragged_splits.flat<int32>()(i - 1), " and ragged_splits(",
                      i, ") = ", ragged_splits.flat<int32>()(i)));
    }
    OP_REQUIRES(context, ragged_splits.flat<int32>()(num_splits - 1) == values_length,
                errors::InvalidArgument(
                    "ragged_splits must end with the length of ragged_values, "
                    "but got ragged_splits(", num_splits - 1, ") = ",
                    ragged_splits.flat<int32>()(num_splits - 1), " and "
                    "ragged_values.length() = ", values_length));

    // Create the output tensor
    Tensor* output = nullptr;
    OP_REQUIRES_OK(context, context->allocate_output(0, ragged_values.shape(),
                                                    &output));

    // Copy the values to the output tensor
    auto output_flat = output->flat<int32>();
    auto values_flat = ragged_values.flat<int32>();
    for (int64 i = 0; i < num_splits; ++i) {
      const int64 start = ragged_splits.flat<int32>()(i);
      const int64 end = ragged_splits.flat<int32>()(i + 1);
      output_flat.Range(start, end).set_value(values_flat.Range(i, i + 1));
    }
  }
};

REGISTER_KERNEL_BUILDER(Name("RaggedTensorToTensor").Device(DEVICE_CPU),
                        RaggedTensorToTensorOp);
