namespace tensorflow {

class RowPartitionOp : public OpKernel {
 public:
  explicit RowPartitionOp(OpKernelConstruction* context) : OpKernel(context) {}

  void Compute(OpKernelContext* context) override {
    const Tensor& row_partition_tensor = context->input(0);
    const Tensor& row_partition_type = context->input(1);
    const Tensor& output_size = context->input(2);

    OP_REQUIRES(context, row_partition_tensor.dims() == 2,
                errors::InvalidArgument("row_partition_tensor must be 2D"));
    OP_REQUIRES(context, row_partition_type.dims() == 0,
                errors::InvalidArgument("row_partition_type must be 0D"));
    OP_REQUIRES(context, output_size.dims() == 1,
                errors::InvalidArgument("output_size must be 1D"));

    const int64 num_partitions = row_partition_tensor.dim_size(0);
    const int64 num_elements = row_partition_tensor.dim_size(1);
    const int64 output_size_val = output_size.flat<int64>()(0);

    OP_REQUIRES(context, num_elements == output_size_val,
                errors::InvalidArgument(
                    "row_partition_tensor must have the same number of "
                    "elements as output_size"));

    // Validate partition size against output size
    for (int64 i = 0; i < num_partitions; ++i) {
      const int64 partition_size = row_partition_tensor.flat<int64>()(i, 0);
      OP_REQUIRES(context, partition_size >= 0,
                  errors::InvalidArgument("partition_size must be non-negative"));
      OP_REQUIRES(context, partition_size <= output_size_val,
                  errors::InvalidArgument(
                      "partition_size must be less than or equal to "
                      "output_size"));
    }

    // Compute output indices
    Tensor* output_indices = nullptr;
    OP_REQUIRES_OK(context, context->allocate_output(0, output_size.shape(),
                                                     &output_indices));

    auto output_indices_flat = output_indices->flat<int64>();
    auto row_partition_tensor_flat = row_partition_tensor.flat<int64>();
    auto row_partition_type_val = row_partition_type.flat<int64>()(0);

    if (row_partition_type_val == 0) {
      // RowPartitionType::kUniform
      for (int64 i = 0; i < output_size_val; ++i) {
        output_indices_flat(i) = i;
      }
    } else if (row_partition_type_val == 1) {
      // RowPartitionType::kNonUniform
      for (int64 i = 0; i < num_partitions; ++i) {
        const int64 partition_size = row_partition_tensor_flat(i, 0);
        for (int64 j = 0; j < partition_size; ++j) {
          output_indices_flat(j) = i;
        }
      }
    } else if (row_partition_type_val == 2) {
      // RowPartitionType::kNonUniformWithOffsets
      for (int64 i = 0; i < num_partitions; ++i) {
        const int64 partition_size = row_partition_tensor_flat(i, 0);
        const int64 offset = row_partition_tensor_flat(i, 1);
        for (int64 j = 0; j < partition_size; ++j) {
          output_indices_flat(j) = offset + j;
        }
      }
    } else {
      OP_REQUIRES(context, false,
                  errors::InvalidArgument("Invalid row_partition_type"));
    }
  }
};

REGISTER_KERNEL_BUILDER(Name("RowPartition").Device(DEVICE_CPU),
                        RowPartitionOp);

}  // namespace tensorflow
