```c
enum imap_status imap_subscribe(struct imap_session *session,
				struct imap_mailbox *mailbox,
				const char *path)
{
	struct imap_command *cmd;
	char *cmd_path;
	enum imap_status status = IMAP_STATUS_ERROR;

	cmd_path = imap_path(session, path);
	if (!cmd_path)
		return status;

	cmd = imap_command(session, "SUBSCRIBE %s", cmd_path);
	if (!cmd)
		goto out;

	status = imap_command_finish(cmd);
	if (status == IMAP_STATUS_OK)
		mailbox->flags |= MAILBOX_FLAG_SUBSCRIBED;
	else
		mailbox->flags &= ~MAILBOX_FLAG_SUBSCRIBED;

out:
	imap_free(&cmd_path);
	return status;
}
