void UnsortedSegmentReduceOp::Compute(OpKernelContext* context) {
  const Tensor& input = context->input(0);
  const Tensor& segment_ids = context->input(1);
  const Tensor& num_segments = context->input(2);
  OP_REQUIRES(context, TensorShapeUtils::IsScalar(num_segments.shape()),
              errors::InvalidArgument("num_segments must be a scalar"));
  OP_REQUIRES(context, TensorShapeUtils::IsVector(segment_ids.shape()),
              errors::InvalidArgument("segment_ids must be a vector"));
  OP_REQUIRES(context, TensorShapeUtils::IsVector(input.shape()),
              errors::InvalidArgument("input must be a vector"));
  OP_REQUIRES(context, input.dims() == 1,
              errors::InvalidArgument("input must be a vector"));
  OP_REQUIRES(context, segment_ids.dims() == 1,
              errors::InvalidArgument("segment_ids must be a vector"));
  OP_REQUIRES(context, input.dim_size(0) == segment_ids.dim_size(0),
              errors::InvalidArgument("input and segment_ids must have the "
                                      "same number of elements"));
  OP_REQUIRES(context, num_segments.scalar<int32>() >= 0,
              errors::InvalidArgument("num_segments must be non-negative"));
  OP_REQUIRES(context, num_segments.scalar<int32>() <= input.dim_size(0),
              errors::InvalidArgument("num_segments must be less than or "
                                      "equal to the number of elements in "
                                      "input"));
  const int32 num_segments_val = num_segments.scalar<int32>()();
  TensorShape output_shape;
  output_shape.AddDim(num_segments_val);
  output_shape.AddDim(input.dim_size(1));
  Tensor* output = nullptr;
  OP_REQUIRES_OK(context, context->allocate_output(0, output_shape, &output));
  OP_REQUIRES_OK(context, UnsortedSegmentReduceImpl(
                              input.flat<T>(), segment_ids.flat<int32>(),
                              num_segments_val, output->flat<T>()));
}

