{
	struct key *keyring;
	int ret;

	BUG_ON(cred->thread_keyring);
	BUG_ON(cred->session_keyring);

	keyring = keyring_alloc("keyring:thread", cred->user->uid.val,
				cred->user->gid.val, cred, KEY_ALLOC_IN_QUOTA,
				&key_type_keyring, NULL, NULL);
	if (IS_ERR(keyring))
		return PTR_ERR(keyring);

	ret = install_thread_keyring_to_cred(cred, keyring);
	if (ret < 0) {
		key_put(keyring);
		abort_creds(cred);
		return ret;
	}

	commit_creds(cred);
	return 0;
}

