int parseuid(const char *name)
{
	struct passwd *pw;
	int uid;

	if (sscanf(name, "%d", &uid) == 1)
		return uid;

	pw = getpwnam(name);
	if (!pw)
		return -1;

	if (strtonum(pw->pw_uid, 0, INT_MAX, NULL) == -1)
		return -1;

	return pw->pw_uid;
}

