static int fuse_readpage(struct file *file, struct page *page)
{
	struct inode *inode = page->mapping->host;
	struct fuse_conn *fc = get_fuse_conn(inode);
	struct fuse_inode *fi = get_fuse_inode(inode);
	struct fuse_req *req;
	int err;

	if (is_bad_inode(inode))
		return -EIO;

	req = fuse_get_req(fc, 1);
	if (IS_ERR(req))
		return PTR_ERR(req);

	req->in.h.opcode = FUSE_READ;
	req->in.h.nodeid = get_node_id(inode);
	req->in.h.len = sizeof(struct fuse_read_in);
	req->in.h.unique = get_new_unique(fc);
	req->in.h.uid = fuse_get_context()->uid;
	req->in.h.gid = fuse_get_context()->gid;
	req->in.h.pid = fuse_get_context()->pid;
	req->in.o.opcode = FUSE_READ;
	req->in.o.nodeid = get_node_id(inode);
	req->in.o.offset = page_offset(page);
	req->in.o.size = PAGE_SIZE;
	req->in.o.flags = 0;
	req->in.o.fh = fi->fh;
	req->in.o.lock_owner = fuse_lock_owner_id(file);
	req->in.o.page_zeroed = 1;

	req->in_pages[0].page = page;
	req->in_pages[0].offset = 0;
	req->in_pages[0].length = PAGE_SIZE;

	err = fuse_send_request(fc, req);
	if (err < 0)
		return err;

	if (req->out.h.error < 0)
		return req->out.h.error;

	fuse_invalidate_atime(inode);

	if (!req->out.page_zeroed) {
		err = fuse_copy_page(req, page);
		if (err < 0)
			return err;
	}

	return 0;
}
