typedef struct {
    int client_socket;
    char buffer[BUFFER_SIZE];
} Connection;

pthread_mutex_t lock_request = PTHREAD_MUTEX_INITIALIZER;

void lock_request() {
    pthread_mutex_lock(&lock_request);
}

void unlock_request() {
    pthread_mutex_unlock(&lock_request);
}

void _handle_single_connection(Connection *conn) {
    int bytes_read;
    char request[BUFFER_SIZE];
    char response[BUFFER_SIZE];

    // Read the request from the client
    bytes_read = read(conn->client_socket, conn->buffer, BUFFER_SIZE - 1);
    if (bytes_read > 0) {
        conn->buffer[bytes_read] = '\0';
        printf("Received request: %s\n", conn->buffer);

        // Process the request
        // For simplicity, let's assume the request is "GET / HTTP/1.1"
        if (strstr(conn->buffer, "GET / HTTP/1.1") != NULL) {
            strcpy(response, "HTTP/1.1 200 OK\r\nContent-Length: 13\r\n\r\nHello, World!");
        } else {
            strcpy(response, "HTTP/1.1 404 Not Found\r\n\r\nNot Found");
        }

        // Send the response back to the client
        write(conn->client_socket, response, strlen(response));

        // Close the connection
        close(conn->client_socket);
    } else {
        close(conn->client_socket);
    }
}

void *handle_connections(void *arg) {
    Connection *conn = (Connection *)arg;
    _handle_single_connection(conn);
    free(conn);
    return NULL;
}

