```cpp
bool ProtocolV2::append_keepalive_ack(KeepAliveFrameAck* ack) {
  if (connection->state != CONNECTED) {
    return false;
  }

  // Encode the keepalive acknowledgment
  const uint8_t* encoded_ack = KeepAliveFrameAck::Encode(ack);
  if (encoded_ack == nullptr) {
    return false;
  }

  // Append the encoded acknowledgment to the outgoing buffer
  connection->outgoing_bl.Append(encoded_ack, ack->encoded_length());
  session_stream_handlers.Append(encoded_ack, ack->encoded_length());

  return true;
}
