static int selinux_netlink_send(struct sk_buff *skb)
{
	struct nlmsghdr *nlh;
	struct security_nlmsg_list *list;
	int rc = 0;

	nlh = nlmsg_hdr(skb);
	list = selinux_nlmsg_list(nlh->nlmsg_type);

	if (list == NULL) {
		rc = selinux_netlink_send_audit(nlh->nlmsg_type, skb->data,
						skb->len);
	} else {
		if (sock_has_perm(skb->sk, list->perms)) {
			rc = -EACCES;
			pr_warn_ratelimited("SELinux:  %s: "
				"permission denied to netlink message type %d\n",
				current->comm, nlh->nlmsg_type);
		} else {
			list->count++;
		}
	}

