```cpp
bool MessageCompressorManager::decompressMessage(MessageCompressorId compressorId,
                                                 const char* compressedData,
                                                 size_t compressedSize,
                                                 char* decompressedData,
                                                 size_t decompressedSizeMax,
                                                 ErrorCodes* error) {
    if (error) {
        *error = ErrorCodes::OK;
    }

    // Check if the compressor is registered
    auto it = compressorMap_.find(compressorId);
    if (it == compressorMap_.end()) {
        if (error) {
            *error = ErrorCodes::InvalidArgument;
        }
        return false;
    }

    // Decompress the message
    size_t decompressedSize;
    if (!it->second->decompress(compressedData, compressedSize, decompressedData,
                                 decompressedSizeMax, &decompressedSize)) {
        if (error) {
            *error = ErrorCodes::InvalidArgument;
        }
        return false;
    }

    // Check if the decompressed size is within the allowed limit
    if (decompressedSize > decompressedSizeMax) {
        if (error) {
            *error = ErrorCodes::InvalidArgument;
        }
        return false;
    }

    return true;
}
