    // Initialize Mongoose library
    mg_init_library(MG_LOG_WARN);

    // Set up SSL configuration
    mg_mgr_init(&mgr, NULL);
    mg_ssl_init(&ssl_config);
    mg_ssl_conf_cert(&ssl_config, SSL_CERTIFICATE, SSL_CERTIFICATE_KEY);
    mg_ssl_conf_ca_cert(&ssl_config, SSL_CA_CERTIFICATE);
    mg_ssl_conf_cipher_list(&ssl_config, SSL_CIPHER_LIST);

    // Validate SSL certificate presence
    if (mg_ssl_conf_cert(&ssl_config, SSL_CERTIFICATE, SSL_CERTIFICATE_KEY) != 0) {
        printf("SSL certificate not found\n");
        exit(1);
    }

    // Set up HTTP/HTTPS ports based on user preferences
    if (HTTP_PORT != 0) {
        mg_bind(&mgr, HTTP_PORT, &http_handler);
    }
    if (HTTPS_PORT != 0) {
        mg_bind_secure(&mgr, HTTPS_PORT, &https_handler, &ssl_config);
    }
}

